import type { FieldDefinition } from "fastschema";

// Node dimensions
export const NODE_WIDTH = 240;
export const NODE_HEIGHT_BASE = 60;
export const FIELD_HEIGHT = 28;

// Dagre layout options
export const DAGRE_OPTIONS = {
  rankdir: "TB" as const,
  ranksep: 40,
  nodesep: 25,
  edgesep: 10,
};

// Connected-component layout options
export const COMPONENT_GAP = 40; // Gap between separate connected components
export const ORPHAN_COLUMNS = 6; // Max columns in orphan schema grid

// Relation type labels
export const RELATION_LABELS: Record<string, string> = {
  o2o: "1:1",
  o2m: "1:n",
  m2m: "n:n",
};

// Relation colors (CSS variable names)
export const RELATION_COLORS: Record<string, string> = {
  o2o: "hsl(var(--relation-o2o))",
  o2m: "hsl(var(--relation-o2m))",
  m2m: "hsl(var(--relation-m2m))",
  default: "hsl(var(--relation-line))",
};

// Field type color classes
export const FIELD_TYPE_COLORS: Record<string, string> = {
  // String types
  string: "text-emerald-600",
  text: "text-emerald-600",
  uuid: "text-emerald-600",
  bytes: "text-emerald-600",

  // Number types
  int: "text-blue-600",
  int8: "text-blue-600",
  int16: "text-blue-600",
  int32: "text-blue-600",
  int64: "text-blue-600",
  uint: "text-blue-600",
  uint8: "text-blue-600",
  uint16: "text-blue-600",
  uint32: "text-blue-600",
  uint64: "text-blue-600",
  float32: "text-blue-600",
  float64: "text-blue-600",

  // Boolean
  bool: "text-amber-600",

  // Date/Time
  time: "text-purple-600",

  // JSON
  json: "text-orange-600",

  // Enum
  enum: "text-indigo-600",

  // File
  file: "text-pink-600",

  // Relation
  relation: "text-info",

  // Default
  default: "text-muted-foreground",
};

/**
 * Get the color class for a field type
 */
export function getFieldTypeColor(type: FieldDefinition["type"]): string {
  return FIELD_TYPE_COLORS[type] || FIELD_TYPE_COLORS.default;
}

/**
 * Get the display label for a relation type
 */
export function getRelationLabel(type: string): string {
  return RELATION_LABELS[type] || type;
}

/**
 * Get the color for a relation type
 */
export function getRelationColor(type: string): string {
  return RELATION_COLORS[type] || RELATION_COLORS.default;
}

/**
 * Calculate node height based on number of fields
 */
export function getNodeHeight(fieldsCount: number): number {
  return NODE_HEIGHT_BASE + fieldsCount * FIELD_HEIGHT;
}

/**
 * Get a display-friendly type name
 */
export function getDisplayTypeName(type: FieldDefinition["type"]): string {
  // Simplify integer types for display
  if (type.startsWith("int") || type.startsWith("uint")) {
    return type === "int" || type === "uint" ? type : type;
  }
  if (type.startsWith("float")) {
    return "float";
  }
  return type;
}

import dagre from "dagre";

import {
  COMPONENT_GAP,
  DAGRE_OPTIONS,
  getNodeHeight,
  NODE_WIDTH,
  ORPHAN_COLUMNS,
} from "./constants";
import {
  buildEdges,
  computeBoundingBox,
  findConnectedComponents,
  translateNodes,
  type BoundingBox,
} from "./graph-utils";

import type {
  LayoutedElements,
  RelationEdgeData,
  SchemaNodeData,
} from "./types";
import type { SchemaDefinition } from "fastschema";
import type { Edge, Node } from "reactflow";

// ============================================================================
// Single-Component Dagre Layout
// ============================================================================

/**
 * Layout a single connected component of schemas using dagre.
 * Returns nodes and edges positioned relative to the component's local origin.
 */
function layoutComponent(
  schemas: SchemaDefinition[],
  allSchemas: SchemaDefinition[],
  direction: "TB" | "LR" = "LR",
): LayoutedElements {
  const dagreGraph = new dagre.graphlib.Graph();
  dagreGraph.setDefaultEdgeLabel(() => ({}));
  dagreGraph.setGraph({
    ...DAGRE_OPTIONS,
    rankdir: direction,
  });

  for (const schema of schemas) {
    const height = getNodeHeight(schema.fields.length);
    dagreGraph.setNode(schema.name, { width: NODE_WIDTH, height });
  }

  for (const schema of schemas) {
    for (const field of schema.fields) {
      const relation = field.relation;
      // Only add edges within this component
      if (
        field.type === "relation" &&
        relation &&
        schemas.some((s) => s.name === relation.schema)
      ) {
        dagreGraph.setEdge(schema.name, relation.schema);
      }
    }
  }

  dagre.layout(dagreGraph);

  const nodes: Node<SchemaNodeData>[] = schemas.map((schema) => {
    const nodeWithPosition = dagreGraph.node(schema.name);
    const height = getNodeHeight(schema.fields.length);
    return {
      id: schema.name,
      type: "schemaNode",
      position: {
        x: nodeWithPosition.x - NODE_WIDTH / 2,
        y: nodeWithPosition.y - height / 2,
      },
      data: {
        schema,
        schemas: allSchemas,
        hoveredField: null,
        hoveredRelation: null,
      },
    };
  });

  const edges = buildEdges(schemas, nodes);

  return { nodes, edges };
}

// ============================================================================
// Orphan Grid Layout
// ============================================================================

/**
 * Layout orphan schemas (no relations) in a compact grid.
 */
function layoutOrphans(
  orphans: SchemaDefinition[],
  allSchemas: SchemaDefinition[],
): Node<SchemaNodeData>[] {
  const columns = Math.min(ORPHAN_COLUMNS, orphans.length);
  const colGap = NODE_WIDTH + 20;
  const nodes: Node<SchemaNodeData>[] = [];

  let col = 0;
  let rowMaxHeight = 0;
  let currentY = 0;

  for (const schema of orphans) {
    const height = getNodeHeight(schema.fields.length);

    nodes.push({
      id: schema.name,
      type: "schemaNode",
      position: {
        x: col * colGap,
        y: currentY,
      },
      data: {
        schema,
        schemas: allSchemas,
        hoveredField: null,
        hoveredRelation: null,
      },
    });

    rowMaxHeight = Math.max(rowMaxHeight, height);
    col++;

    if (col >= columns) {
      col = 0;
      currentY += rowMaxHeight + 30;
      rowMaxHeight = 0;
    }
  }

  return nodes;
}

// ============================================================================
// Row-Based Component Packing
// ============================================================================

/**
 * Max width for a row of components. Components are placed left-to-right
 * and wrap to the next row when this width would be exceeded.
 * Tuned so that 2-3 medium components fit side-by-side.
 */
const MAX_ROW_WIDTH = 2400;

interface LayoutedComponent {
  nodes: Node<SchemaNodeData>[];
  edges: Edge<RelationEdgeData>[];
  bb: BoundingBox;
}

/**
 * Arrange pre-layouted components in rows (left-to-right, top-to-bottom).
 * Similar to CSS flex-wrap: wrap.
 */
function arrangeComponentsInGrid(layouted: LayoutedComponent[]): void {
  let rowX = 0;
  let rowY = 0;
  let rowMaxHeight = 0;

  for (const comp of layouted) {
    // Wrap to next row if this component would exceed the max width
    if (rowX > 0 && rowX + comp.bb.width > MAX_ROW_WIDTH) {
      rowX = 0;
      rowY += rowMaxHeight + COMPONENT_GAP;
      rowMaxHeight = 0;
    }

    translateNodes(comp.nodes, rowX, rowY);

    // Update bounding box after translation
    comp.bb = computeBoundingBox(comp.nodes);

    rowX += comp.bb.width + COMPONENT_GAP;
    rowMaxHeight = Math.max(rowMaxHeight, comp.bb.height);
  }
}

// ============================================================================
// Main Layout Function
// ============================================================================

/**
 * Calculate layout using connected-component extraction + dagre + grid arrangement.
 *
 * Strategy:
 * 1. Find connected components (groups of schemas linked by relations)
 * 2. Layout each component independently with dagre
 * 3. Arrange component bounding boxes in rows (left-to-right, wrapping)
 * 4. Place orphan schemas (no relations) in a compact grid below the components
 */
export function getLayoutedElements(
  schemas: SchemaDefinition[],
  direction: "TB" | "LR" = "LR",
): LayoutedElements {
  if (schemas.length === 0) {
    return { nodes: [], edges: [] };
  }

  const { components, orphans } = findConnectedComponents(schemas);

  // Layout each component independently
  const layoutedComponents: LayoutedComponent[] = components.map(
    (component) => {
      const { nodes, edges } = layoutComponent(component, schemas, direction);
      const bb = computeBoundingBox(nodes);
      return { nodes, edges, bb };
    },
  );

  // Arrange components in a 2D grid (row-based packing)
  arrangeComponentsInGrid(layoutedComponents);

  const allNodes: Node<SchemaNodeData>[] = [];
  for (const comp of layoutedComponents) {
    allNodes.push(...comp.nodes);
  }

  // Find the bottom of all components to place orphans below
  const componentsBB = computeBoundingBox(allNodes);
  const orphanStartY =
    allNodes.length > 0 ? componentsBB.maxY + COMPONENT_GAP : 0;

  // Layout orphans in a grid below all components
  if (orphans.length > 0) {
    const orphanNodes = layoutOrphans(orphans, schemas);
    translateNodes(orphanNodes, 0, orphanStartY);
    allNodes.push(...orphanNodes);
  }

  // Rebuild all edges with updated node positions (handles depend on final positions)
  const finalEdges = buildEdges(schemas, allNodes);

  return { nodes: allNodes, edges: finalEdges };
}

import { toPng, toSvg } from "html-to-image";
import { Download, FileCode, ImageIcon, Plus, RotateCcw } from "lucide-react";
import { useCallback, useRef } from "react";
import ReactFlow, {
  Background,
  BackgroundVariant,
  ConnectionMode,
  Controls,
  Panel,
  ReactFlowProvider,
} from "reactflow";
import "reactflow/dist/style.css";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";

import { useDiagram } from "./hooks/use-diagram";
import { useHoverHighlight } from "./hooks/use-hover-highlight";
import { SchemaNode } from "./schema-node";

import type { DiagramPanelProps } from "./types";
import type React from "react";
import type { NodeTypes } from "reactflow";

const nodeTypes: NodeTypes = {
  schemaNode: SchemaNode,
};

/**
 * Empty state component when no schemas are provided
 */
function EmptyState() {
  return (
    <div className="bg-muted/30 flex flex-1 items-center justify-center">
      <div className="text-muted-foreground text-center">
        <div className="bg-muted mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full">
          <svg
            className="h-8 w-8"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={1.5}
              d="M4 7v10c0 2.21 3.582 4 8 4s8-1.79 8-4V7M4 7c0 2.21 3.582 4 8 4s8-1.79 8-4M4 7c0-2.21 3.582-4 8-4s8 1.79 8 4m0 5c0 2.21-3.582 4-8 4s-8-1.79-8-4"
            />
          </svg>
        </div>
        <h3 className="mb-1 font-medium">No Schema Yet</h3>
        <p className="max-w-[250px] text-sm">
          Add schemas to visualize your data model as an ER diagram
        </p>
      </div>
    </div>
  );
}

/**
 * Inner diagram panel component (requires ReactFlowProvider)
 */
const DiagramPanelInner: React.FC<DiagramPanelProps> = ({
  schemas,
  readOnly = false,
  className,
  onSchemaAdd,
  onEditSchema,
  onAddField,
  onEditField,
  onDeleteField,
}) => {
  const reactFlowWrapper = useRef<HTMLDivElement>(null);

  const {
    hoveredField,
    hoveredRelation,
    handleFieldHover,
    handleEdgeMouseEnter,
    handleEdgeMouseLeave,
  } = useHoverHighlight();

  const { nodes, edges, onNodesChange, onEdgesChange, resetLayout } =
    useDiagram({
      schemas,
      readOnly,
      hoveredField,
      hoveredRelation,
      onEditSchema,
      onAddField,
      onEditField,
      onDeleteField,
      onFieldHover: handleFieldHover,
    });

  const handleExportImage = useCallback(async (format: "png" | "svg") => {
    const element = document.querySelector(".react-flow") as HTMLElement;
    if (!element) {
      toast.error("Could not find diagram to export");
      return;
    }

    try {
      const dataUrl =
        format === "png"
          ? await toPng(element, {
              backgroundColor: "var(--background)",
              quality: 1,
              pixelRatio: 2,
            })
          : await toSvg(element, {
              backgroundColor: "var(--background)",
            });

      const link = document.createElement("a");
      link.download = `schema-diagram.${format}`;
      link.href = dataUrl;
      link.click();
      toast.success(`Diagram exported as ${format.toUpperCase()}`);
    } catch (error) {
      // eslint-disable-next-line no-console
      console.error("Export failed:", error);
      toast.error("Failed to export diagram");
    }
  }, []);

  if (schemas.length === 0) {
    return <EmptyState />;
  }

  return (
    <div
      ref={reactFlowWrapper}
      className={cn("relative flex-1", className)}
    >
      <ReactFlow
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onEdgeMouseEnter={handleEdgeMouseEnter}
        onEdgeMouseLeave={handleEdgeMouseLeave}
        nodeTypes={nodeTypes}
        connectionMode={ConnectionMode.Loose}
        fitView
        fitViewOptions={{ padding: 0.2, minZoom: 0.4 }}
        minZoom={0.1}
        maxZoom={5}
        defaultEdgeOptions={{
          type: "smoothstep",
          style: { stroke: "hsl(var(--relation-line))" },
        }}
      >
        <Background
          variant={BackgroundVariant.Dots}
          gap={20}
          size={1}
          color="hsl(var(--border))"
        />
        <Controls showInteractive={false} />

        <Panel
          position="top-right"
          className="flex gap-2"
        >
          {!readOnly && onSchemaAdd && (
            <Button
              variant="default"
              size="sm"
              onClick={onSchemaAdd}
              className="bg-primary"
            >
              <Plus className="mr-2 h-4 w-4" />
              Create Schema
            </Button>
          )}
          <Button
            variant="outline"
            size="sm"
            onClick={resetLayout}
            className="bg-background"
          >
            <RotateCcw className="mr-2 h-4 w-4" />
            Reset Layout
          </Button>
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="outline"
                size="sm"
                className="bg-background"
              >
                <Download className="mr-2 h-4 w-4" />
                Export
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuItem onClick={() => handleExportImage("png")}>
                <ImageIcon className="mr-2 h-4 w-4" />
                Export as PNG
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => handleExportImage("svg")}>
                <FileCode className="mr-2 h-4 w-4" />
                Export as SVG
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </Panel>
      </ReactFlow>
    </div>
  );
};

/**
 * Schema Diagram Panel component
 *
 * Displays an ER diagram visualization of schema definitions using ReactFlow.
 * Supports interactive editing of schemas and fields when not in read-only mode.
 *
 * @example
 * ```tsx
 * <DiagramPanel
 *   schemas={schemas}
 *   onSchemaEdit={(schema) => console.log('Edit schema', schema)}
 *   onFieldAdd={(schemaName) => console.log('Add field to', schemaName)}
 * />
 * ```
 */
export const DiagramPanel: React.FC<DiagramPanelProps> = (props) => {
  return (
    <ReactFlowProvider>
      <DiagramPanelInner {...props} />
    </ReactFlowProvider>
  );
};

import { MarkerType } from "reactflow";

import { getNodeHeight, getRelationColor, getRelationLabel, NODE_WIDTH } from "./constants";

import type { RelationEdgeData, SchemaNodeData } from "./types";
import type { FieldDefinition, SchemaDefinition } from "fastschema";
import type { Edge, Node } from "reactflow";

// ============================================================================
// Connected-Component Extraction
// ============================================================================

/**
 * Find connected components in the schema graph using BFS.
 * Schemas connected by relations (directly or transitively) form a component.
 * Schemas with no relations are treated as orphans.
 */
export function findConnectedComponents(schemas: SchemaDefinition[]): {
  components: SchemaDefinition[][];
  orphans: SchemaDefinition[];
} {
  const schemaMap = new Map<string, SchemaDefinition>();
  for (const s of schemas) {
    schemaMap.set(s.name, s);
  }

  // Build adjacency list (only for schemas that exist in the input)
  const adjacency = new Map<string, Set<string>>();
  for (const s of schemas) {
    adjacency.set(s.name, new Set());
  }

  for (const schema of schemas) {
    for (const field of schema.fields) {
      if (
        field.type === "relation" &&
        field.relation &&
        schemaMap.has(field.relation.schema)
      ) {
        // Both names were seeded into `adjacency` above, so reads are present.
        adjacency.get(schema.name)?.add(field.relation.schema);
        adjacency.get(field.relation.schema)?.add(schema.name);
      }
    }
  }

  // Separate orphans (no edges) from connected schemas
  const orphans: SchemaDefinition[] = [];
  const connectedSchemaNames = new Set<string>();

  for (const schema of schemas) {
    if ((adjacency.get(schema.name)?.size ?? 0) === 0) {
      orphans.push(schema);
    } else {
      connectedSchemaNames.add(schema.name);
    }
  }

  // BFS to find connected components among connected schemas
  const visited = new Set<string>();
  const components: SchemaDefinition[][] = [];

  for (const name of connectedSchemaNames) {
    if (visited.has(name)) continue;

    const component: SchemaDefinition[] = [];
    const queue = [name];
    visited.add(name);

    while (queue.length > 0) {
      const current = queue.shift();
      if (current === undefined) break;

      const currentSchema = schemaMap.get(current);
      if (currentSchema) component.push(currentSchema);

      for (const neighbor of adjacency.get(current) ?? []) {
        if (!visited.has(neighbor) && connectedSchemaNames.has(neighbor)) {
          visited.add(neighbor);
          queue.push(neighbor);
        }
      }
    }

    components.push(component);
  }

  // Sort components by size (largest first) for better visual arrangement
  components.sort((a, b) => b.length - a.length);

  return { components, orphans };
}

// ============================================================================
// Bounding Box Utilities
// ============================================================================

export interface BoundingBox {
  minX: number;
  minY: number;
  maxX: number;
  maxY: number;
  width: number;
  height: number;
}

/**
 * Compute bounding box for a set of nodes (accounting for node dimensions).
 */
export function computeBoundingBox(nodes: Node<SchemaNodeData>[]): BoundingBox {
  if (nodes.length === 0) {
    return { minX: 0, minY: 0, maxX: 0, maxY: 0, width: 0, height: 0 };
  }

  let minX = Infinity;
  let minY = Infinity;
  let maxX = -Infinity;
  let maxY = -Infinity;

  for (const node of nodes) {
    const h = getNodeHeight(node.data.schema.fields.length);
    minX = Math.min(minX, node.position.x);
    minY = Math.min(minY, node.position.y);
    maxX = Math.max(maxX, node.position.x + NODE_WIDTH);
    maxY = Math.max(maxY, node.position.y + h);
  }

  return {
    minX,
    minY,
    maxX,
    maxY,
    width: maxX - minX,
    height: maxY - minY,
  };
}

/**
 * Translate a set of nodes so the bounding box origin is at (offsetX, offsetY).
 */
export function translateNodes(
  nodes: Node<SchemaNodeData>[],
  offsetX: number,
  offsetY: number,
): void {
  const bb = computeBoundingBox(nodes);
  const dx = offsetX - bb.minX;
  const dy = offsetY - bb.minY;
  for (const node of nodes) {
    node.position.x += dx;
    node.position.y += dy;
  }
}

// ============================================================================
// Edge Creation
// ============================================================================

/**
 * Create edges with proper source/target handles based on relative node positions.
 */
export function buildEdges(
  schemas: SchemaDefinition[],
  nodes: Node<SchemaNodeData>[],
): Edge<RelationEdgeData>[] {
  const edges: Edge<RelationEdgeData>[] = [];
  const nodePositions = new Map(nodes.map((n) => [n.id, n.position]));
  const processedEdges = new Set<string>();

  for (const schema of schemas) {
    for (const field of schema.fields) {
      if (field.type === "relation" && field.relation) {
        const sourcePos = nodePositions.get(schema.name);
        const targetPos = nodePositions.get(field.relation.schema);

        if (!sourcePos || !targetPos) continue;

        const edgeId = `${schema.name}-${field.name}-${field.relation.schema}-${field.relation.field}`;
        const reverseEdgeId = `${field.relation.schema}-${field.relation.field}-${schema.name}-${field.name}`;

        if (processedEdges.has(reverseEdgeId)) continue;
        processedEdges.add(edgeId);

        const sourceIsLeft = sourcePos.x < targetPos.x;
        const sourceHandle = sourceIsLeft
          ? `${field.name}-right`
          : `${field.name}-left`;
        const targetHandle = sourceIsLeft
          ? `${field.relation.field}-left`
          : `${field.relation.field}-right`;

        const relationType = field.relation.type;
        const relationColor = getRelationColor(relationType);
        const relationLabel = getRelationLabel(relationType);
        const isOwner = field.relation.owner === true;
        const isM2M = relationType === "m2m";

        const edgeConfig: Edge<RelationEdgeData> = {
          id: edgeId,
          source: schema.name,
          target: field.relation.schema,
          sourceHandle,
          targetHandle,
          type: "default",
          animated: false,
          label: relationLabel,
          labelStyle: {
            fontSize: 10,
            fontWeight: 500,
            fill: "var(--muted-foreground)",
          },
          labelBgStyle: {
            fill: "var(--background)",
            fillOpacity: 0.9,
          },
          labelBgPadding: [4, 2] as [number, number],
          labelBgBorderRadius: 4,
          style: {
            stroke: relationColor,
            strokeWidth: 1.5,
          },
          data: {
            sourceField: field.name,
            targetField: field.relation.field,
            relationType,
            relationColor,
          },
        };

        if (isM2M) {
          edgeConfig.markerStart = {
            type: MarkerType.ArrowClosed,
            color: relationColor,
            width: 10,
            height: 10,
          };
          edgeConfig.markerEnd = {
            type: MarkerType.ArrowClosed,
            color: relationColor,
            width: 10,
            height: 10,
          };
        } else if (isOwner) {
          edgeConfig.markerEnd = {
            type: MarkerType.ArrowClosed,
            color: relationColor,
            width: 10,
            height: 10,
          };
        } else {
          edgeConfig.markerStart = {
            type: MarkerType.ArrowClosed,
            color: relationColor,
            width: 10,
            height: 10,
          };
        }

        edges.push(edgeConfig);
      }
    }
  }

  return edges;
}

/**
 * Update edge handles when nodes are moved
 */
export function updateEdgesForMovedNode(
  nodes: Node[],
  edges: Edge<RelationEdgeData>[],
): Edge<RelationEdgeData>[] {
  const nodePositions = new Map(nodes.map((n) => [n.id, n.position]));

  return edges.map((edge) => {
    const sourcePos = nodePositions.get(edge.source);
    const targetPos = nodePositions.get(edge.target);

    if (!sourcePos || !targetPos || !edge.data) return edge;

    const sourceIsLeft = sourcePos.x < targetPos.x;
    const sourceHandle = sourceIsLeft
      ? `${edge.data.sourceField}-right`
      : `${edge.data.sourceField}-left`;
    const targetHandle = sourceIsLeft
      ? `${edge.data.targetField}-left`
      : `${edge.data.targetField}-right`;

    return {
      ...edge,
      sourceHandle,
      targetHandle,
    };
  });
}

/**
 * Get the index of a field in a schema
 */
export function getFieldIndexInSchema(
  schema: SchemaDefinition,
  fieldName: string,
): number {
  return schema.fields.findIndex((f: FieldDefinition) => f.name === fieldName);
}

import { useCallback, useEffect, useRef } from "react";
import { useNodesState, useEdgesState } from "reactflow";

import { getLayoutedElements, updateEdgesForMovedNode } from "../layout-utils";

import type {
  DiagramCallbacks,
  HoveredRelation,
  RelationEdgeData,
  SchemaNodeData,
} from "../types";
import type { FieldDefinition, SchemaDefinition } from "fastschema";
import type { Edge, Node, NodeChange } from "reactflow";

interface UseDiagramOptions extends DiagramCallbacks {
  schemas: SchemaDefinition[];
  readOnly?: boolean;
  hoveredField: string | null;
  hoveredRelation: HoveredRelation | null;
  onFieldHover: (
    schemaName: string,
    fieldName: string | null,
    field: FieldDefinition | null,
  ) => void;
}

export function useDiagram({
  schemas,
  readOnly = false,
  hoveredField,
  hoveredRelation,
  onEditSchema,
  onAddField,
  onEditField,
  onDeleteField,
  onFieldHover,
}: UseDiagramOptions) {
  const [nodes, setNodes, onNodesChange] = useNodesState<SchemaNodeData>([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState<RelationEdgeData>([]);

  // Use refs for callbacks to avoid re-running layout effect
  const callbacksRef = useRef({
    onEditSchema,
    onAddField,
    onEditField,
    onDeleteField,
    onFieldHover,
  });

  // Update refs when callbacks change
  useEffect(() => {
    callbacksRef.current = {
      onEditSchema,
      onAddField,
      onEditField,
      onDeleteField,
      onFieldHover,
    };
  }, [onEditSchema, onAddField, onEditField, onDeleteField, onFieldHover]);

  // Create stable callback handlers that use refs
  const handleEditSchema = useCallback(
    (schema: SchemaDefinition) => {
      if (!readOnly) {
        callbacksRef.current.onEditSchema?.(schema);
      }
    },
    [readOnly],
  );

  const handleAddField = useCallback(
    (schemaName: string) => {
      if (!readOnly) {
        callbacksRef.current.onAddField?.(schemaName);
      }
    },
    [readOnly],
  );

  const handleEditField = useCallback(
    (schemaName: string, field: FieldDefinition) => {
      if (!readOnly) {
        callbacksRef.current.onEditField?.(schemaName, field);
      }
    },
    [readOnly],
  );

  const handleDeleteField = useCallback(
    (schemaName: string, fieldName: string) => {
      if (!readOnly) {
        callbacksRef.current.onDeleteField?.(schemaName, fieldName);
      }
    },
    [readOnly],
  );

  const handleFieldHover = useCallback(
    (
      schemaName: string,
      fieldName: string | null,
      field: FieldDefinition | null,
    ) => {
      callbacksRef.current.onFieldHover?.(schemaName, fieldName, field);
    },
    [],
  );

  // Update node data when hover state or readOnly changes
  useEffect(() => {
    setNodes((nds) =>
      nds.map((node) => ({
        ...node,
        data: {
          ...node.data,
          hoveredField,
          hoveredRelation,
          readOnly,
          onEditSchema: handleEditSchema,
          onAddField: handleAddField,
          onEditField: handleEditField,
          onDeleteField: handleDeleteField,
          onFieldHover: handleFieldHover,
        },
      })),
    );

    // Highlight edges based on hover (animation only)
    setEdges((eds) =>
      eds.map((edge) => {
        const isHovered =
          hoveredRelation &&
          edge.data?.sourceField === hoveredRelation.sourceField &&
          edge.source === hoveredRelation.source;

        return {
          ...edge,
          animated: isHovered as boolean | undefined,
        };
      }),
    );
  }, [
    hoveredField,
    hoveredRelation,
    readOnly,
    handleEditSchema,
    handleAddField,
    handleEditField,
    handleDeleteField,
    handleFieldHover,
    setNodes,
    setEdges,
  ]);

  // Handle node drag to update edge positions
  const handleNodesChange = useCallback(
    (changes: NodeChange[]) => {
      onNodesChange(changes);

      // After node movement, update edge handles
      const hasMoved = changes.some((c) => c.type === "position" && c.position);
      if (hasMoved) {
        setTimeout(() => {
          setNodes((currentNodes) => {
            setEdges((currentEdges) =>
              updateEdgesForMovedNode(
                currentNodes,
                currentEdges as Edge<RelationEdgeData>[],
              ),
            );
            return currentNodes;
          });
        }, 0);
      }
    },
    [onNodesChange, setNodes, setEdges],
  );

  // Initialize layout when schemas change (only schemas, not callbacks)
  useEffect(() => {
    if (schemas.length === 0) {
      setNodes([]);
      setEdges([]);
      return;
    }

    const { nodes: layoutedNodes, edges: layoutedEdges } =
      getLayoutedElements(schemas);

    // Add callbacks to node data
    const nodesWithCallbacks: Node<SchemaNodeData>[] = layoutedNodes.map(
      (node) => ({
        ...node,
        data: {
          ...node.data,
          schemas,
          hoveredField,
          hoveredRelation,
          readOnly,
          onEditSchema: handleEditSchema,
          onAddField: handleAddField,
          onEditField: handleEditField,
          onDeleteField: handleDeleteField,
          onFieldHover: handleFieldHover,
        },
      }),
    );

    setNodes(nodesWithCallbacks);
    setEdges(layoutedEdges);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [schemas]);

  // Reset layout function
  const resetLayout = useCallback(() => {
    const { nodes: layoutedNodes, edges: layoutedEdges } =
      getLayoutedElements(schemas);

    const nodesWithCallbacks: Node<SchemaNodeData>[] = layoutedNodes.map(
      (node) => ({
        ...node,
        data: {
          ...node.data,
          schemas,
          hoveredField,
          hoveredRelation,
          readOnly,
          onEditSchema: handleEditSchema,
          onAddField: handleAddField,
          onEditField: handleEditField,
          onDeleteField: handleDeleteField,
          onFieldHover: handleFieldHover,
        },
      }),
    );

    setNodes(nodesWithCallbacks);
    setEdges(layoutedEdges);
  }, [
    schemas,
    hoveredField,
    hoveredRelation,
    readOnly,
    handleEditSchema,
    handleAddField,
    handleEditField,
    handleDeleteField,
    handleFieldHover,
    setNodes,
    setEdges,
  ]);

  return {
    nodes,
    edges,
    onNodesChange: handleNodesChange,
    onEdgesChange,
    resetLayout,
  };
}

import { useCallback, useState } from "react";

import type { HoveredRelation } from "../types";
