export function useHoverHighlight() {
  const [hoveredField, setHoveredField] = useState<string | null>(null);
  const [hoveredRelation, setHoveredRelation] =
    useState<HoveredRelation | null>(null);

  const handleFieldHover = useCallback(
    (
      schemaName: string,
      fieldName: string | null,
      field: FieldDefinition | null,
    ) => {
      if (fieldName && field && field.type === "relation" && field.relation) {
        setHoveredField(`${schemaName}.${fieldName}`);
        setHoveredRelation({
          source: schemaName,
          target: field.relation.schema,
          sourceField: fieldName,
          targetField: field.relation.field,
        });
      } else {
        setHoveredField(null);
        setHoveredRelation(null);
      }
    },
    [],
  );

  const handleEdgeMouseEnter = useCallback(
    (_: React.MouseEvent, edge: Edge) => {
      if (edge.data?.sourceField && edge.data?.targetField) {
        setHoveredRelation({
          source: edge.source,
          target: edge.target,
          sourceField: edge.data.sourceField,
          targetField: edge.data.targetField,
        });
      }
    },
    [],
  );

  const handleEdgeMouseLeave = useCallback(() => {
    setHoveredRelation(null);
  }, []);

  const clearHover = useCallback(() => {
    setHoveredField(null);
    setHoveredRelation(null);
  }, []);

  return {
    hoveredField,
    hoveredRelation,
    handleFieldHover,
    handleEdgeMouseEnter,
    handleEdgeMouseLeave,
    clearHover,
  };
}

