/**
 * Check if a field is highlighted based on the current hover state
 */
function isFieldHighlighted(
  field: FieldDefinition,
  schemaName: string,
  hoveredRelation: SchemaNodeData["hoveredRelation"],
): boolean {
  if (!hoveredRelation) return false;

  // Check if this field is part of the hovered relation
  if (
    hoveredRelation.source === schemaName &&
    hoveredRelation.sourceField === field.name
  ) {
    return true;
  }
  if (
    hoveredRelation.target === schemaName &&
    hoveredRelation.targetField === field.name
  ) {
    return true;
  }
  return false;
}

