        )}

        {/* General handles for node connections */}
        <Handle
          type="target"
          position={Position.Left}
          id="left"
          className="!bg-schema-border !border-background !-left-1.5 !h-3 !w-3 !border-2 opacity-0"
        />
        <Handle
          type="source"
          position={Position.Right}
          id="right"
          className="!bg-schema-border !border-background !-right-1.5 !h-3 !w-3 !border-2 opacity-0"
        />
