/**
 * Relation info for hover highlighting
 */
export interface HoveredRelation {
  source: string;
  target: string;
  sourceField: string;
  targetField: string;
}

/**
 * Data passed to each schema node
 */
export interface SchemaNodeData {
  [key: string]: unknown;
  schema: SchemaDefinition;
  schemas: SchemaDefinition[];
  hoveredField: string | null;
  hoveredRelation: HoveredRelation | null;
  readOnly?: boolean;
  onEditSchema?: (schema: SchemaDefinition) => void;
  onAddField?: (schemaName: string) => void;
  onEditField?: (schemaName: string, field: FieldDefinition) => void;
  onDeleteField?: (schemaName: string, fieldName: string) => void;
  onFieldHover?: (
    schemaName: string,
    fieldName: string | null,
    field: FieldDefinition | null,
  ) => void;
}

/**
 * Edge data for relation edges
 */
export interface RelationEdgeData {
  [key: string]: unknown;
  sourceField: string;
  targetField: string;
  relationType: FieldRelation["type"];
  relationColor: string;
}

/**
 * Layout result from dagre
 */
export interface LayoutedElements {
  nodes: Node<SchemaNodeData>[];
  edges: Edge<RelationEdgeData>[];
}

/**
 * Callbacks for diagram interactions
 */
export interface DiagramCallbacks {
  onSchemaClick?: (schemaName: string) => void;
  onFieldClick?: (schemaName: string, fieldName: string) => void;
  onSchemaAdd?: () => void;
  onEditSchema?: (schema: SchemaDefinition) => void;
  onAddField?: (schemaName: string) => void;
  onEditField?: (schemaName: string, field: FieldDefinition) => void;
  onDeleteField?: (schemaName: string, fieldName: string) => void;
  onLayoutChange?: (
    positions: Record<string, { x: number; y: number }>,
  ) => void;
}

/**
 * Diagram component props
 */
export interface DiagramPanelProps extends DiagramCallbacks {
  schemas: SchemaDefinition[];
  readOnly?: boolean;
  className?: string;
}

/**
 * Position for node layout
 */
export interface NodePosition {
  x: number;
  y: number;
}

