export const SchemasDiagramPage = () => {
  const { fastschema } = useFastSchema();
  const { appConfig } = fastschema.state();

  // Force re-render counter - incremented after schema changes to refresh the diagram
  const [, forceUpdate] = useState(0);

  // Track which schema is currently being edited
  const [editingSchemaName, setEditingSchemaName] = useState<string | null>(
    null,
  );

  // Track if schema settings dialog is open
  const [schemaSettingsOpen, setSchemaSettingsOpen] = useState(false);

  // Track if we're creating a new schema
  const [isCreatingSchema, setIsCreatingSchema] = useState(false);

  // Filter out junction schemas (auto-generated for m2m relations)
  const schemas = useMemo(
    () => (appConfig?.schemas ?? []).filter((s) => !s.is_junction_schema),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [appConfig?.schemas, forceUpdate],
  );

  // Helper to refresh schemas after changes
  const refreshSchemas = useCallback(async () => {
    await fastschema.init();
    forceUpdate((n) => n + 1);
  }, [fastschema]);

  // Find the schema being edited
  const editingSchema = useMemo(
    () => schemas.find((s) => s.name === editingSchemaName),
    [schemas, editingSchemaName],
  );

  // Get the current schema definition (either editing or creating new)
  const currentSchemaDefinition = useMemo(
    () => (isCreatingSchema ? schemaDefinitionDefaultValues : editingSchema),
    [isCreatingSchema, editingSchema],
  );

  // Create a form for the currently editing schema
  const schemaForm = useForm({
    defaultValues: currentSchemaDefinition ?? schemaDefinitionDefaultValues,
    validators: {
      onChange: schemaDefinitionSchema,
    },
  });

  // Track previous schema definition to detect changes
  const prevSchemaDefRef = useRef(currentSchemaDefinition);

  // Reset form when editing schema changes or when switching to create mode
  useEffect(() => {
    if (currentSchemaDefinition !== prevSchemaDefRef.current) {
      schemaForm.reset(
        currentSchemaDefinition ?? schemaDefinitionDefaultValues,
      );
      prevSchemaDefRef.current = currentSchemaDefinition;
    }
  }, [currentSchemaDefinition, schemaForm]);

  // Listen for editing field store changes to detect when a field dialog closes
  const editingField = useStore(editingFieldStore, (s) => s);

  // Save schema changes to the server
  const saveSchemaChanges = useCallback(
    async (schemaName: string, newValues: SchemaDefinition) => {
      const originalSchema = schemas.find((s) => s.name === schemaName);
      if (
        originalSchema &&
        JSON.stringify(originalSchema) !== JSON.stringify(newValues)
      ) {
        try {
          await fastschema.schemas().update(schemaName, { schema: newValues });
          toast.success(`Schema "${schemaName}" updated successfully`);
          await refreshSchemas();
        } catch (error) {
          toast.error(
            `Failed to update schema: ${error instanceof Error ? error.message : "Unknown error"}`,
          );
        }
      }
    },
    [schemas, fastschema, refreshSchemas],
  );

  // Save schema changes when field dialog closes
  useEffect(() => {
    if (!editingField && editingSchemaName && !schemaSettingsOpen) {
      const currentValues = schemaForm.state.values;
      const schemaNameToSave = editingSchemaName;
      // Reset editing state immediately to prevent re-triggers
      setEditingSchemaName(null);
      // Save asynchronously
      saveSchemaChanges(schemaNameToSave, currentValues);
    }
  }, [
    editingField,
    editingSchemaName,
    schemaSettingsOpen,
    schemaForm.state.values,
    saveSchemaChanges,
  ]);

  // Create context value
  const contextValue: SchemaEditContextType = useMemo(
    () => ({
      form: schemaForm,
      schemaDefinition:
        currentSchemaDefinition ?? schemaDefinitionDefaultValues,
      getSchemas: () => schemas,
    }),
    [schemaForm, currentSchemaDefinition, schemas],
  );

  // Handler for creating a new schema
  const handleSchemaAdd = useCallback(() => {
    setIsCreatingSchema(true);
    setSchemaSettingsOpen(true);
  }, []);

  // Handlers for diagram interactions
  const handleSchemaEdit = useCallback((schema: SchemaDefinition) => {
    setIsCreatingSchema(false);
    setEditingSchemaName(schema.name);
    setSchemaSettingsOpen(true);
  }, []);

  // Save new schema to the server
  const createSchema = useCallback(
    async (newSchema: SchemaDefinition) => {
      if (!newSchema.name) {
        toast.error("Schema name is required");
        return false;
      }

      // Ensure schema has at least one field with label_field set
      // Backend requires label_field to be set
      let schemaToCreate = newSchema;
      if (newSchema.fields.length === 0) {
        const defaultField = {
          type: "uuid" as const,
          name: "id",
          label: "ID",
          optional: false,
        };
        schemaToCreate = {
          ...newSchema,
          fields: [defaultField],
          label_field: "id",
        };
      } else if (!newSchema.label_field) {
        // If there are fields but no label_field, use the first string field or first field
        const stringField = newSchema.fields.find((f) => f.type === "string");
        const labelField = stringField?.name || newSchema.fields[0]?.name || "";
        schemaToCreate = {
          ...newSchema,
          label_field: labelField,
        };
      }

      try {
        await fastschema.schemas().create(schemaToCreate);
        toast.success(`Schema "${newSchema.name}" created successfully`);
        await refreshSchemas();
        return true;
      } catch (error) {
        toast.error(
          `Failed to create schema: ${error instanceof Error ? error.message : "Unknown error"}`,
        );
        return false;
      }
    },
    [fastschema, refreshSchemas],
  );

  // Handle saving schema settings
  const handleSaveSchemaSettings = useCallback(async () => {
    const currentValues = schemaForm.state.values;

    if (isCreatingSchema) {
      // Create new schema
      const success = await createSchema(currentValues);
      if (success) {
        setIsCreatingSchema(false);
        setSchemaSettingsOpen(false);
      }
    } else if (editingSchemaName) {
      // Save changes
      await saveSchemaChanges(editingSchemaName, currentValues);
      setEditingSchemaName(null);
      setSchemaSettingsOpen(false);
    }
  }, [
    isCreatingSchema,
    editingSchemaName,
    schemaForm.state.values,
    saveSchemaChanges,
    createSchema,
  ]);

  // Handle dialog close (only close, no save)
  const handleSchemaSettingsClose = useCallback((open: boolean) => {
    if (!open) {
      // Just close without saving
      setIsCreatingSchema(false);
      setEditingSchemaName(null);
    }
    setSchemaSettingsOpen(open);
  }, []);

  const handleFieldAdd = useCallback((schemaName: string) => {
    setEditingSchemaName(schemaName);
    editingFieldStore.setState({
      field: fieldDefaultValues,
      zoneId: "main",
    });
  }, []);

  const handleFieldEdit = useCallback(
    (schemaName: string, field: FieldDefinition) => {
      setEditingSchemaName(schemaName);
      editingFieldStore.setState({
        field,
      });
    },
    [],
  );

  const handleFieldDelete = useCallback(
    (schemaName: string, fieldName: string) => {
      const schema = schemas.find((s) => s.name === schemaName);
      if (!schema) return;

      // eslint-disable-next-line no-alert
      if (!confirm(`Are you sure you want to delete field "${fieldName}"?`)) {
        return;
      }

      const updatedSchema: SchemaDefinition = {
        ...schema,
        fields: schema.fields.filter((f) => f.name !== fieldName),
      };

      fastschema
        .schemas()
        .update(schemaName, { schema: updatedSchema })
        .then(async () => {
          toast.success(`Field "${fieldName}" deleted successfully`);
          await refreshSchemas();
        })
        .catch((error) => {
          toast.error(`Failed to delete field: ${error.message}`);
        });
    },
    [schemas, fastschema, refreshSchemas],
  );

  // Handle deleting the currently editing schema
  const handleSchemaDelete = useCallback(async () => {
    if (!editingSchemaName) return;

    if (
      // eslint-disable-next-line no-alert
      !confirm(
        `Are you sure you want to delete schema "${editingSchemaName}"? This action cannot be undone.`,
      )
    ) {
      return;
    }

    try {
      await fastschema.schemas().delete(editingSchemaName);
      toast.success(`Schema "${editingSchemaName}" deleted successfully`);
      setEditingSchemaName(null);
      setSchemaSettingsOpen(false);
      await refreshSchemas();
    } catch (error) {
      toast.error(
        `Failed to delete schema: ${error instanceof Error ? error.message : "Unknown error"}`,
      );
    }
  }, [editingSchemaName, fastschema, refreshSchemas]);

  return (
    <SchemaEditContext.Provider value={contextValue}>
      <div className="flex h-full w-full overflow-hidden">
        <DiagramPanel
          schemas={schemas}
          onSchemaAdd={handleSchemaAdd}
          onEditSchema={handleSchemaEdit}
          onAddField={handleFieldAdd}
          onEditField={handleFieldEdit}
          onDeleteField={handleFieldDelete}
        />

        {/* Field Editor Dialog */}
        <SchemaEditField schemaForm={schemaForm} />

        {/* Schema Settings Dialog */}
        <TabDialog
          open={schemaSettingsOpen}
          onOpenChange={handleSchemaSettingsClose}
          title={
            isCreatingSchema
              ? "Create New Schema"
              : `Schema Settings: ${editingSchemaName ?? ""}`
          }
          description={
            isCreatingSchema
              ? "Configure your new schema."
              : "Manage your schema settings and preferences."
          }
          tabs={schemaSettingsTabs}
          actions={{
            left: !isCreatingSchema && editingSchemaName && (
              <Button
                type="button"
                variant="destructive"
                size="sm"
                className="cursor-pointer"
                onClick={handleSchemaDelete}
              >
                <Trash2 className="mr-2 h-4 w-4" />
                Delete Schema
              </Button>
            ),
            right: (
              <Button
                type="button"
                size="sm"
                className="cursor-pointer"
                onClick={handleSaveSchemaSettings}
              >
                {isCreatingSchema ? "Create" : "Save"}
              </Button>
            ),
          }}
        />
      </div>
    </SchemaEditContext.Provider>
  );
};
